/** Call-by-value, Call-by-name, and Call-by-need Jam interpreter */

import java.io.IOException;
import java.io.Reader;

/** Exception thrown when an evaluation error occurs. */
class EvalException extends RuntimeException {
  EvalException(String msg) { super(msg); }
}

/** A class that implements call-by-value, call-by-name, and call-by-need interpretation of Jam programs. */
class Interpreter {

  /** The parsed program for this interpreter. */
  AST prog;

  /** Constructor for a program given in a file. */
  public Interpreter(String fileName) throws IOException {
    Parser p = new Parser(fileName);
    prog = p.parse();
  }

  /** Constructor for a program already embedded in a Parser object. */
  public Interpreter(Parser p) {
    prog = p.parse();
  }

  /** Constructor for a program embedded in a Reader. */
  public Interpreter(Reader reader) {
    Parser p = new Parser(reader);
    prog = p.parse();
  }

  /** Evaluates the program using call-by-value semantics. */
  public JamVal callByValue() { return prog.accept(valueEvalVisitor); }

  /** Evaluates the program using call-by-name semantics. */
  public JamVal callByName() { return prog.accept(nameEvalVisitor); }

  /** Evaluates the program using call-by-need semantics. */
  public JamVal callByNeed() { return prog.accept(needEvalVisitor); }

  /** An unevaluated expression paired with the evaluator (environment) in which it should be evaluated. */
  private static class ConcreteSuspension implements Suspension {
    private AST exp;
    private EvalVisitor ev;

    ConcreteSuspension(AST a, EvalVisitor e) { exp = a; ev = e; }

    AST exp() { return exp; }
    EvalVisitor ev() { return ev; }
    void putEv(EvalVisitor e) { ev = e; }

    /** Evaluates this suspension by running exp in ev's environment. */
    public JamVal eval() {
      return exp.accept(ev);
    }

    public String toString() { return "<" + exp + ", " + ev + ">"; }
  }

  /** Binding used in CBV evaluation: the value is pre-evaluated at binding creation time. */
  private static class ValueBinding extends Binding {
    ValueBinding(Variable v, JamVal jv) { super(v, jv); }
    /** Returns the pre-evaluated value. */
    public JamVal value() { return value; }
    /** No-op: CBV bindings are immutable once created. */
    public void setBinding(Suspension s) { /* no-op */ }
    public String toString() { return "[" + var + ", " + value + "]"; }
  }

  /** Binding used in CBName evaluation: the suspension is re-evaluated on every access. */
  private static class NameBinding extends Binding {
    protected Suspension susp;
    NameBinding(Variable v, Suspension s) {
      super(v, null);
      susp = s;
    }
    /** Evaluates and returns the suspension (no caching). */
    public JamVal value() { return susp.eval(); }
    /** Updates the stored suspension. */
    public void setBinding(Suspension s) { susp = s; }
    public String toString() { return "[" + var + ", " + susp + "]"; }
  }

  /** Binding used in CBNeed evaluation: the suspension is evaluated once and its result is cached. */
  private static class NeedBinding extends NameBinding {
    NeedBinding(Variable v, Suspension s) { super(v, s); }
    /** Returns cached value if available; evaluates and caches the suspension on first access. */
    public JamVal value() {
      if (value == null) {
        value = susp.eval();
      }
      return value;
    }
    public String toString() { return "[" + var + ", " + value + ", " + susp + "]"; }
  }

  /** Looks up a variable in an environment (PureList of Bindings) and returns its value. */
  private static class LookupVisitor implements PureListVisitor<Binding, JamVal> {

    /** The variable to look up. Uniqueness of Variable objects allows == comparison. */
    Variable var;

    LookupVisitor(Variable v) { var = v; }

    /** Variable not found — throw an eval error. */
    public JamVal forEmpty(Empty<Binding> e) {
      throw new EvalException("Unbound variable `" + var + "'");
    }

    /** If the head binding matches, return its value; otherwise recurse on the tail. */
    public JamVal forCons(Cons<Binding> c) {
      Binding b = c.first();
      if (b.var() == var) return b.value();
      return c.rest().accept(this);
    }
  }

  /** Strategy interface for creating bindings, encapsulating the difference between CBV, CBNm, and CBNd. */
  private interface EvalPolicy {
    /** Creates the appropriate binding for var bound to the expression ast, evaluated using evaluator ev. */
    Binding newBinding(Variable var, AST ast, EvalVisitor ev);
  }

  /** AST visitor that evaluates expressions using the embedded environment and eval policy. */
  private static class EvalVisitor implements ASTVisitor<JamVal> {

    private PureList<Binding> env;
    private EvalPolicy evalPolicy;

    /** Constructor for recursive invocations with a specific environment. */
    private EvalVisitor(PureList<Binding> e, EvalPolicy ep) {
      env = e;
      evalPolicy = ep;
    }

    /** Top-level constructor with empty environment. */
    public EvalVisitor(EvalPolicy ep) { this(new Empty<Binding>(), ep); }

    /** Creates a new EvalVisitor with the given environment but the same eval policy. */
    public EvalVisitor newVisitor(PureList<Binding> e) {
      return new EvalVisitor(e, evalPolicy);
    }

    /** Creates a binding for var bound to ast using this visitor's eval policy. */
    public Binding newBinding(Variable var, AST ast) {
      return evalPolicy.newBinding(var, ast, this);
    }

    /** Returns the current environment. */
    public PureList<Binding> env() { return env; }

    /** Boolean constants are self-evaluating. */
    public JamVal forBoolConstant(BoolConstant b) { return b; }

    /** Integer constants are self-evaluating. */
    public JamVal forIntConstant(IntConstant i) { return i; }

    /** The empty list constant evaluates to the JamEmpty singleton. */
    public JamVal forEmptyConstant(EmptyConstant n) { return JamEmpty.ONLY; }

    /** Variables are looked up in the current environment. */
    public JamVal forVariable(Variable v) {
      return env.accept(new LookupVisitor(v));
    }

    /** Primitive functions are self-evaluating values. */
    public JamVal forPrimFun(PrimFun f) { return f; }

    /** Evaluates the argument and applies the unary operator. */
    public JamVal forUnOpApp(UnOpApp u) {
      JamVal val = u.arg().accept(this);
      return u.rator().accept(new StandardUnOpVisitor(val));
    }

    /** Delegates to StandardBinOpVisitor (supports short-circuit & and |). */
    public JamVal forBinOpApp(BinOpApp b) {
      return b.rator().accept(new StandardBinOpVisitor(b.arg1(), b.arg2(), this));
    }

    /** Evaluates the rator, then applies the resulting function to the unevaluated args. */
    public JamVal forApp(App a) {
      JamVal funVal = a.rator().accept(this);
      if (!(funVal instanceof JamFun))
        throw new EvalException("Application of non-function: " + funVal);
      return ((JamFun) funVal).accept(new StandardFunVisitor(a.args(), this));
    }

    /** A map expression creates a closure capturing the current environment. */
    public JamVal forMap(Map m) {
      return new JamClosure(m, env);
    }

    /** Evaluates the test; if true, evaluates the consequent; otherwise the alternative. */
    public JamVal forIf(If i) {
      JamVal testVal = i.test().accept(this);
      if (!(testVal instanceof BoolConstant))
        throw new EvalException("Non-boolean test in if: " + testVal);
      if (testVal == BoolConstant.TRUE) return i.conseq().accept(this);
      else return i.alt().accept(this);
    }

    /** Evaluates a non-recursive let by creating bindings in the current environment
      * (equivalent to (map v1,...,vn to body)(M1,...,Mn)), then evaluating the body. */
    public JamVal forLet(Let l) {
      Def[] defs = l.defs();
      // Build new env by prepending all bindings (using current 'this' as evaluator for all RHSs)
      PureList<Binding> newEnv = env;
      for (int i = defs.length - 1; i >= 0; i--) {
        Binding b = newBinding(defs[i].lhs(), defs[i].rhs());
        newEnv = newEnv.cons(b);
      }
      return l.body().accept(newVisitor(newEnv));
    }
  }

  /** Top-level EvalVisitors implementing CBV, CBNm, and CBNd evaluation. */
  private static EvalVisitor valueEvalVisitor = new EvalVisitor(CallByValue.ONLY);
  private static EvalVisitor nameEvalVisitor = new EvalVisitor(CallByName.ONLY);
  private static EvalVisitor needEvalVisitor = new EvalVisitor(CallByNeed.ONLY);

  /** Applies a JamFun to argument expressions.  For closures, bindings are created per the eval policy
    * (eager for CBV, suspended for CBNm/CBNd).  For primitive functions, args are always evaluated eagerly. */
  private static class StandardFunVisitor implements JamFunVisitor<JamVal> {

    /** Unevaluated argument expressions. */
    AST[] args;

    /** Evaluator at the call site; used to create bindings and evaluate args. */
    EvalVisitor evalVisitor;

    StandardFunVisitor(AST[] asts, EvalVisitor ev) {
      args = asts;
      evalVisitor = ev;
    }

    /** Eagerly evaluates all arguments (used for primitive functions). */
    private JamVal[] evalArgs() {
      JamVal[] vals = new JamVal[args.length];
      for (int i = 0; i < args.length; i++) {
        vals[i] = args[i].accept(evalVisitor);
      }
      return vals;
    }

    /** Applies a user-defined closure: extends the closure's environment with new bindings (one per param),
      * then evaluates the closure body in the extended environment. */
    public JamVal forJamClosure(JamClosure closure) {
      Variable[] vars = closure.code().vars();
      if (vars.length != args.length)
        throw new EvalException("Closure of arity " + vars.length + " applied to " + args.length + " args");
      // Start from the closure's captured environment and prepend new bindings
      PureList<Binding> newEnv = closure.env();
      for (int i = vars.length - 1; i >= 0; i--) {
        Binding b = evalVisitor.newBinding(vars[i], args[i]);
        newEnv = newEnv.cons(b);
      }
      return closure.code().body().accept(evalVisitor.newVisitor(newEnv));
    }

    /** Applies a primitive function: evaluates all args eagerly, then dispatches to the prim fun visitor. */
    public JamVal forPrimFun(PrimFun primFun) {
      JamVal[] vals = evalArgs();
      return primFun.accept(new StandardPrimFunVisitor(vals));
    }
  }

  /** CBV policy: evaluates argument immediately and stores the resulting value. */
  private static class CallByValue implements EvalPolicy {

    public static final EvalPolicy ONLY = new CallByValue();
    private CallByValue() { }

    /** Returns a ValueBinding holding the eagerly evaluated argument. */
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new ValueBinding(var, arg.accept(ev));
    }
  }

  /** CBName policy: wraps each argument expression in a suspension so it is re-evaluated on every use. */
  private static class CallByName implements EvalPolicy {
    public static final EvalPolicy ONLY = new CallByName();
    private CallByName() {}

    /** Returns a NameBinding with a suspension of the arg in the call-site environment. */
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NameBinding(var, new ConcreteSuspension(arg, ev));
    }
  }

  /** CBNeed policy: wraps each argument expression in a caching suspension (evaluated at most once). */
  private static class CallByNeed implements EvalPolicy {
    public static final EvalPolicy ONLY = new CallByNeed();
    private CallByNeed() {}

    /** Returns a NeedBinding with a suspension of the arg in the call-site environment. */
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NeedBinding(var, new ConcreteSuspension(arg, ev));
    }
  }

  /** Evaluates unary operator applications given the already-evaluated operand. */
  private static class StandardUnOpVisitor implements UnOpVisitor<JamVal> {
    private final JamVal val;
    StandardUnOpVisitor(JamVal jv) { val = jv; }

    /** Confirms val is an IntConstant; throws EvalException otherwise. */
    private IntConstant checkInteger(String op) {
      if (!(val instanceof IntConstant))
        throw new EvalException("Unary `" + op + "' applied to non-integer: " + val);
      return (IntConstant) val;
    }

    /** Confirms val is a BoolConstant; throws EvalException otherwise. */
    private BoolConstant checkBoolean(String op) {
      if (!(val instanceof BoolConstant))
        throw new EvalException("Unary `" + op + "' applied to non-boolean: " + val);
      return (BoolConstant) val;
    }

    /** Unary + is the identity on integers. */
    public JamVal forUnOpPlus() { return checkInteger("+"); }
    /** Unary - negates an integer. */
    public JamVal forUnOpMinus() { return new IntConstant(-checkInteger("-").value()); }
    /** Logical not (~) negates a boolean. */
    public JamVal forOpTilde() { return checkBoolean("~").not(); }
  }

  /** Evaluates binary operator applications. The operands are passed as unevaluated ASTs to support
    * short-circuit evaluation of & and |. */
  private static class StandardBinOpVisitor implements BinOpVisitor<JamVal> {
    private AST arg1, arg2;
    private EvalVisitor evalVisitor;

    StandardBinOpVisitor(AST a1, AST a2, EvalVisitor ev) { arg1 = a1; arg2 = a2; evalVisitor = ev; }

    /** Evaluates the given arg and confirms it is an IntConstant. */
    private IntConstant evalIntegerArg(AST arg, String op) {
      JamVal val = arg.accept(evalVisitor);
      if (!(val instanceof IntConstant))
        throw new EvalException("Binary `" + op + "' applied to non-integer: " + val);
      return (IntConstant) val;
    }

    /** Evaluates the given arg and confirms it is a BoolConstant. */
    private BoolConstant evalBooleanArg(AST arg, String op) {
      JamVal val = arg.accept(evalVisitor);
      if (!(val instanceof BoolConstant))
        throw new EvalException("Binary `" + op + "' applied to non-boolean: " + val);
      return (BoolConstant) val;
    }

    public JamVal forBinOpPlus() {
      return new IntConstant(evalIntegerArg(arg1, "+").value() + evalIntegerArg(arg2, "+").value());
    }
    public JamVal forBinOpMinus() {
      return new IntConstant(evalIntegerArg(arg1, "-").value() - evalIntegerArg(arg2, "-").value());
    }
    public JamVal forOpTimes() {
      return new IntConstant(evalIntegerArg(arg1, "*").value() * evalIntegerArg(arg2, "*").value());
    }
    public JamVal forOpDivide() {
      int divisor = evalIntegerArg(arg2, "/").value();
      if (divisor == 0) throw new EvalException("Division by zero");
      return new IntConstant(evalIntegerArg(arg1, "/").value() / divisor);
    }

    /** Jam equality: structural for non-functions, reference identity for JamFun values. */
    public JamVal forOpEquals() {
      JamVal v1 = arg1.accept(evalVisitor);
      JamVal v2 = arg2.accept(evalVisitor);
      return BoolConstant.toBoolConstant(jamEqual(v1, v2));
    }

    public JamVal forOpNotEquals() {
      JamVal v1 = arg1.accept(evalVisitor);
      JamVal v2 = arg2.accept(evalVisitor);
      return BoolConstant.toBoolConstant(!jamEqual(v1, v2));
    }

    /** Returns true iff v1 and v2 are Jam-equal: identity for JamFun, structural for everything else. */
    private boolean jamEqual(JamVal v1, JamVal v2) {
      // Functions compare by identity (reference equality)
      if (v1 instanceof JamFun || v2 instanceof JamFun) return v1 == v2;
      return v1.equals(v2);
    }

    public JamVal forOpLessThan() {
      return BoolConstant.toBoolConstant(
        evalIntegerArg(arg1, "<").value() < evalIntegerArg(arg2, "<").value());
    }
    public JamVal forOpGreaterThan() {
      return BoolConstant.toBoolConstant(
        evalIntegerArg(arg1, ">").value() > evalIntegerArg(arg2, ">").value());
    }
    public JamVal forOpLessThanEquals() {
      return BoolConstant.toBoolConstant(
        evalIntegerArg(arg1, "<=").value() <= evalIntegerArg(arg2, "<=").value());
    }
    public JamVal forOpGreaterThanEquals() {
      return BoolConstant.toBoolConstant(
        evalIntegerArg(arg1, ">=").value() >= evalIntegerArg(arg2, ">=").value());
    }

    /** Short-circuit AND: returns false immediately if the first operand is false. */
    public JamVal forOpAnd() {
      BoolConstant b1 = evalBooleanArg(arg1, "&");
      if (b1 == BoolConstant.FALSE) return BoolConstant.FALSE;
      return evalBooleanArg(arg2, "&");
    }

    /** Short-circuit OR: returns true immediately if the first operand is true. */
    public JamVal forOpOr() {
      BoolConstant b1 = evalBooleanArg(arg1, "|");
      if (b1 == BoolConstant.TRUE) return BoolConstant.TRUE;
      return evalBooleanArg(arg2, "|");
    }
  }

  /** Implements each Jam primitive function given pre-evaluated arguments. */
  private static class StandardPrimFunVisitor implements PrimFunVisitor<JamVal> {

    /** Pre-evaluated arguments to the primitive function application. */
    JamVal[] vals;

    StandardPrimFunVisitor(JamVal[] vls) { vals = vls; }

    /** Throws EvalException for incorrect argument count. */
    private JamVal primFunError(String fn) {
      throw new EvalException("Primitive function `" + fn + "' applied to " + vals.length + " arguments");
    }

    /** Confirms vals[0] is a JamCons (used by first and rest). */
    private JamCons confirmJamCons(String funName) {
      if (vals.length != 1) primFunError(funName);
      if (!(vals[0] instanceof JamCons))
        throw new EvalException("`" + funName + "' applied to non-cons: " + vals[0]);
      return (JamCons) vals[0];
    }

    /** Returns the arity of a JamFun (number of parameters it accepts). */
    private IntConstant jamArity(JamFun f) {
      return f.accept(new JamFunVisitor<IntConstant>() {
        public IntConstant forJamClosure(JamClosure c) {
          return new IntConstant(c.code().vars().length);
        }
        public IntConstant forPrimFun(PrimFun pf) {
          return pf.accept(new PrimFunVisitor<IntConstant>() {
            public IntConstant forFunctionPPrim() { return new IntConstant(1); }
            public IntConstant forNumberPPrim()   { return new IntConstant(1); }
            public IntConstant forListPPrim()     { return new IntConstant(1); }
            public IntConstant forConsPPrim()     { return new IntConstant(1); }
            public IntConstant forEmptyPPrim()    { return new IntConstant(1); }
            public IntConstant forArityPrim()     { return new IntConstant(1); }
            public IntConstant forConsPrim()      { return new IntConstant(2); }
            public IntConstant forFirstPrim()     { return new IntConstant(1); }
            public IntConstant forRestPrim()      { return new IntConstant(1); }
          });
        }
      });
    }

    /** function?(v): true iff v is a JamFun (closure or primitive). */
    public JamVal forFunctionPPrim() {
      if (vals.length != 1) return primFunError("function?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamFun);
    }

    /** number?(v): true iff v is an integer. */
    public JamVal forNumberPPrim() {
      if (vals.length != 1) return primFunError("number?");
      return BoolConstant.toBoolConstant(vals[0] instanceof IntConstant);
    }

    /** list?(v): true iff v is a JamList (empty or cons). */
    public JamVal forListPPrim() {
      if (vals.length != 1) return primFunError("list?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamList);
    }

    /** cons?(v): true iff v was created by cons (i.e., is a JamCons). */
    public JamVal forConsPPrim() {
      if (vals.length != 1) return primFunError("cons?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamCons);
    }

    /** empty?(v): true iff v is the empty list. */
    public JamVal forEmptyPPrim() {
      if (vals.length != 1) return primFunError("empty?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamEmpty);
    }

    /** cons(v, lst): prepends v to list lst; throws if lst is not a list. */
    public JamVal forConsPrim() {
      if (vals.length != 2) return primFunError("cons");
      if (!(vals[1] instanceof JamList))
        throw new EvalException("`cons' second argument is not a list: " + vals[1]);
      return new JamCons(vals[0], (JamList) vals[1]);
    }

    /** arity(f): returns the number of parameters of function f; throws if f is not a function. */
    public JamVal forArityPrim() {
      if (vals.length != 1) return primFunError("arity");
      if (!(vals[0] instanceof JamFun))
        throw new EvalException("`arity' applied to non-function: " + vals[0]);
      return jamArity((JamFun) vals[0]);
    }

    /** first(lst): returns the first element of a non-empty list. */
    public JamVal forFirstPrim() {
      return confirmJamCons("first").first();
    }

    /** rest(lst): returns the tail of a non-empty list. */
    public JamVal forRestPrim() {
      return confirmJamCons("rest").rest();
    }
  }
}

import java.util.StringTokenizer;
import junit.framework.TestCase;
import java.io.*;

/** Agent-written tests for the Jam interpreter covering edge cases. */
public class AgentTest extends TestCase {

  public AgentTest(String name) { super(name); }

  private void valueCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-value " + name, answer, interp.callByValue().toString());
  }

  private void nameCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-name " + name, answer, interp.callByName().toString());
  }

  private void needCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-need " + name, answer, interp.callByNeed().toString());
  }

  private void allCheck(String name, String answer, String program) {
    valueCheck(name, answer, program);
    nameCheck(name, answer, program);
    needCheck(name, answer, program);
  }

  // ======= Basic constants and operations =======

  public void testFalseConstant() {
    allCheck("false", "false", "false");
  }

  public void testEmptyConstant() {
    allCheck("empty", "()", "empty");
  }

  public void testUnaryPlus() {
    allCheck("unaryPlus", "5", "+5");
  }

  public void testUnaryMinus() {
    allCheck("unaryMinus", "-3", "- 3");
  }

  public void testLogicalNot() {
    allCheck("not", "false", "~true");
    allCheck("not2", "true", "~false");
  }

  public void testDivide() {
    allCheck("divide", "3", "7 / 2");
  }

  // ======= Relational operators =======

  public void testLessThan() {
    allCheck("lt1", "true", "3 < 5");
    allCheck("lt2", "false", "5 < 3");
    allCheck("lt3", "false", "3 < 3");
  }

  public void testGreaterThan() {
    allCheck("gt1", "false", "3 > 5");
    allCheck("gt2", "true", "5 > 3");
  }

  public void testLessThanEquals() {
    allCheck("lte1", "true", "3 <= 3");
    allCheck("lte2", "true", "2 <= 3");
    allCheck("lte3", "false", "4 <= 3");
  }

  public void testGreaterThanEquals() {
    allCheck("gte1", "true", "3 >= 3");
    allCheck("gte2", "false", "2 >= 3");
  }

  public void testNotEquals() {
    allCheck("neq1", "true", "3 != 4");
    allCheck("neq2", "false", "3 != 3");
  }

  // ======= Short-circuit operators =======

  public void testShortCircuitAndFalse() {
    // false & <anything> should not evaluate second arg
    allCheck("scAnd", "false", "false & (1 / 0 = 0)");
  }

  public void testShortCircuitOrTrue() {
    // true | <anything> should not evaluate second arg
    allCheck("scOr", "true", "true | (1 / 0 = 0)");
  }

  public void testAndBothTrue() {
    allCheck("andTrue", "true", "true & true");
  }

  public void testOrBothFalse() {
    allCheck("orFalse", "false", "false | false");
  }

  // ======= If-then-else =======

  public void testIfTrue() {
    allCheck("ifTrue", "1", "if true then 1 else 2");
  }

  public void testIfFalse() {
    allCheck("ifFalse", "2", "if false then 1 else 2");
  }

  public void testIfOnlyEvalsBranch() {
    // Only the chosen branch should be evaluated
    allCheck("ifBranch", "42", "if true then 42 else (1/0)");
  }

  public void testIfNonBooleanTest() {
    try {
      allCheck("ifNonBool", "x", "if 1 then 2 else 3");
      fail("Expected EvalException");
    } catch (EvalException e) { /* expected */ }
  }

  // ======= List operations =======

  public void testConsList() {
    allCheck("consList", "(1 2 3)", "cons(1, cons(2, cons(3, empty)))");
  }

  public void testFirst() {
    allCheck("first", "1", "first(cons(1, cons(2, empty)))");
  }

  public void testRest() {
    allCheck("rest", "(2 3)", "rest(cons(1, cons(2, cons(3, empty))))");
  }

  public void testEmptyP() {
    allCheck("emptyP1", "true", "empty?(empty)");
    allCheck("emptyP2", "false", "empty?(cons(1, empty))");
  }

  public void testConsP() {
    allCheck("consP1", "false", "cons?(empty)");
    allCheck("consP2", "true", "cons?(cons(1, empty))");
  }

  public void testListP() {
    allCheck("listP1", "true", "list?(empty)");
    allCheck("listP2", "true", "list?(cons(1, empty))");
    allCheck("listP3", "false", "list?(42)");
    allCheck("listP4", "false", "list?(true)");
  }

  public void testNumberP() {
    allCheck("numberP1", "true", "number?(42)");
    allCheck("numberP2", "false", "number?(true)");
    allCheck("numberP3", "false", "number?(empty)");
  }

  public void testFunctionP() {
    allCheck("functionP1", "true", "function?(cons)");
    allCheck("functionP2", "true", "function?(map x to x)");
    allCheck("functionP3", "false", "function?(42)");
    allCheck("functionP4", "false", "function?(true)");
  }

  public void testFirstOnEmpty() {
    try {
      allCheck("firstEmpty", "x", "first(empty)");
      fail("Expected EvalException for first on empty");
    } catch (EvalException e) { /* expected */ }
  }

  public void testConsSecondNotList() {
    try {
      allCheck("consNotList", "x", "cons(1, 2)");
      fail("Expected EvalException for cons with non-list second arg");
    } catch (EvalException e) { /* expected */ }
  }

  // ======= Arity =======

  public void testArityMap() {
    allCheck("arityMap0", "0", "arity(map to 1)");
    allCheck("arityMap1", "1", "arity(map x to x)");
    allCheck("arityMap2", "2", "arity(map x,y to x + y)");
  }

  public void testArityPrimFuns() {
    allCheck("arityCons", "2", "arity(cons)");
    allCheck("arityFirst", "1", "arity(first)");
    allCheck("arityRest", "1", "arity(rest)");
    allCheck("arityEmpty?", "1", "arity(empty?)");
    allCheck("arityCons?", "1", "arity(cons?)");
    allCheck("arityList?", "1", "arity(list?)");
    allCheck("arityNumber?", "1", "arity(number?)");
    allCheck("arityFunction?", "1", "arity(function?)");
    allCheck("arityArity", "1", "arity(arity)");
  }

  public void testArityOnNonFunction() {
    try {
      allCheck("arityNonFun", "x", "arity(42)");
      fail("Expected EvalException for arity on non-function");
    } catch (EvalException e) { /* expected */ }
  }

  // ======= Equality =======

  public void testIntEquality() {
    allCheck("intEq1", "true", "5 = 5");
    allCheck("intEq2", "false", "5 = 6");
  }

  public void testBoolEquality() {
    allCheck("boolEq1", "true", "true = true");
    allCheck("boolEq2", "false", "true = false");
  }

  public void testListEquality() {
    allCheck("listEq1", "true", "cons(1,cons(2,empty))=cons(1,cons(2,empty))");
    allCheck("listEq2", "false", "cons(1,cons(2,empty))=cons(1,cons(3,empty))");
    allCheck("listEq3", "false", "cons(1,cons(2,empty))=cons(1,empty)");
    allCheck("emptyEq", "true", "empty = empty");
  }

  public void testPrimFunEquality() {
    allCheck("primFunEq1", "true", "cons? = cons?");
    allCheck("primFunEq2", "false", "cons? = empty?");
    allCheck("primFunEq3", "false", "cons? = (map x to x)");
  }

  public void testClosureReferenceEquality() {
    // Two distinct map expressions are not equal
    allCheck("closureNeq", "false", "(map x to x) = (map x to x)");
  }

  public void testClosureSameObjectCBV() {
    // CBV: binding is evaluated once, same closure object used twice
    valueCheck("sameClosureCBV", "true",
      "let m := map x to x; in m = m");
  }

  public void testClosureSameObjectCBName() {
    // CBName: binding is re-evaluated each use — two different closures
    nameCheck("sameClosureCBN", "false",
      "let m := map x to x; in m = m");
  }

  public void testClosureSameObjectCBNeed() {
    // CBNeed: binding is evaluated once (cached) — same closure object
    needCheck("sameClosureCBNeed", "true",
      "let m := map x to x; in m = m");
  }

  // ======= Let and Map =======

  public void testSimpleLet() {
    allCheck("simpleLet", "5", "let x := 5; in x");
  }

  public void testLetMultipleBindings() {
    allCheck("letMulti", "7", "let x := 3; y := 4; in x + y");
  }

  public void testLetShadowing() {
    allCheck("letShadow", "2", "let x := 1; in let x := 2; in x");
  }

  public void testMapApplication() {
    allCheck("mapApp", "6", "(map x to x + 1)(5)");
  }

  public void testMapMultiArgs() {
    allCheck("mapMulti", "7", "(map x,y to x + y)(3, 4)");
  }

  public void testArityMismatch() {
    try {
      allCheck("arityMismatch", "x", "(map x to x)(1, 2)");
      fail("Expected EvalException for arity mismatch");
    } catch (EvalException e) { /* expected */ }
  }

  public void testMapEmpty() {
    allCheck("mapEmpty", "42", "(map to 42)()");
  }

  // ======= CBName vs CBValue difference =======

  public void testCBVEvaluatesUnusedArgs() {
    // In CBV, this will throw because the argument 1/0 is evaluated eagerly
    try {
      valueCheck("cbvEval", "x", "(map x,y to x)(1, 1/0)");
      fail("Expected EvalException in CBV for unused arg 1/0");
    } catch (EvalException e) { /* expected */ }
  }

  public void testCBNameSkipsUnusedArgs() {
    // In CBName, 1/0 is never evaluated if y is never used
    nameCheck("cbnSkip", "1", "(map x,y to x)(1, 1/0)");
  }

  public void testCBNeedSkipsUnusedArgs() {
    // Same for CBNeed
    needCheck("cbneedSkip", "1", "(map x,y to x)(1, 1/0)");
  }

  // ======= Y-combinator tests =======

  public void testValueYFactorial() {
    try {
      String output = "720";
      String input =
        "let  Y := map f to let g := map x to f(map z to (x(x))(z)); in g(g);" +
        "  FACT := map f to map n to if n = 0 then 1 else n * f(n - 1);" +
        "in (Y(FACT))(6)";
      valueCheck("valueYFactorial", output, input);
    } catch (Exception e) {
      e.printStackTrace();
      fail("valueYFactorial threw " + e);
    }
  }

  public void testNameYFactorial() {
    try {
      String output = "720";
      String input =
        "let   Y := map f to let g := map x to f(x(x)); in g(g);" +
        "   FACT := map f to map n to if n = 0 then 1 else n * f(n - 1); in (Y(FACT))(6)";
      nameCheck("nameYFactorial", output, input);
    } catch (Exception e) {
      e.printStackTrace();
      fail("nameYFactorial threw " + e);
    }
  }

  public void testNeedYFactorial() {
    try {
      String output = "720";
      String input =
        "let   Y := map f to let g := map x to f(x(x)); in g(g); " +
        "   FACT := map f to map n to if n = 0 then 1 else n * f(n - 1); in (Y(FACT))(6)";
      needCheck("needYFactorial", output, input);
    } catch (Exception e) {
      e.printStackTrace();
      fail("needYFactorial threw " + e);
    }
  }

  public void testYAppend() {
    try {
      String output = "(1 2 3 1 2 3)";
      String input =
        "let    Y := map f to let g := map x to f(map z1,z2 to (x(x))(z1,z2)); in g(g);" +
        "  APPEND := map ap to map x,y to if empty?(x) then y else cons(first(x), ap(rest(x), y));" +
        "       l := cons(1,cons(2,cons(3,empty)));" +
        "in (Y(APPEND))(l,l)";
      allCheck("yappend", output, input);
    } catch (Exception e) {
      e.printStackTrace();
      fail("yappend threw " + e);
    }
  }

  public void testFib() {
    try {
      String output = "((0 1) (1 1) (2 2) (3 3) (4 5) (5 8) (6 13) (7 21) (8 34) (9 55) (10 89))";
      String input =
        "let      Y := map f to let g := map x to f(x(x)); in g(g); " +
        "      pair := map x,y to cons(x, cons(y, empty));" +
        "   FIBHELP := map fibhelp to map k,fn,fnm1 to if k = 0 then fn else fibhelp(k - 1, fn + fnm1, fn); " +
        "in let FFIB := map ffib to map n to if n = 0 then 1 else (Y(FIBHELP))(n - 1,1,1); " +
        "   in let FIBS := map fibs to map k,l to " +
        "                    let fibk := (Y(FFIB))(k);" +
        "                    in if k >= 0 then fibs(k - 1, cons(pair(k,fibk), l)) else l; " +
        "      in (Y(FIBS))(10, empty)";
      needCheck("fib-need", output, input);
      nameCheck("fib-name", output, input);
    } catch (Exception e) {
      e.printStackTrace();
      fail("fib threw " + e);
    }
  }
}

