+
+  public void testFalseConstant() {
+    allCheck("false", "false", "false");
+  }
+
+  public void testEmptyConstant() {
+    allCheck("empty", "()", "empty");
+  }
+
+  public void testUnaryPlus() {
+    allCheck("unaryPlus", "5", "+5");
+  }
+
+  public void testUnaryMinus() {
+    allCheck("unaryMinus", "-3", "- 3");
+  }
+
+  public void testLogicalNot() {
+    allCheck("not", "false", "~true");
+    allCheck("not2", "true", "~false");
+  }
+
+  public void testDivide() {
+    allCheck("divide", "3", "7 / 2");
+  }
+
+  // ======= Relational operators =======
+
+  public void testLessThan() {
+    allCheck("lt1", "true", "3 < 5");
+    allCheck("lt2", "false", "5 < 3");
+    allCheck("lt3", "false", "3 < 3");
+  }
+
+  public void testGreaterThan() {
+    allCheck("gt1", "false", "3 > 5");
+    allCheck("gt2", "true", "5 > 3");
+  }
+
+  public void testLessThanEquals() {
